#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int l,r,id;
}a[N];

bool operator<(Node x,Node y){
    return x.r>y.r;
}

bool cmp(Node x,Node y){
    return x.l<y.l;
}

int n,num[N],tot;
priority_queue<Node> q;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&a[i].l,&a[i].r);
        a[i].id=i;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++){
        if(q.empty() || q.top().r>=a[i].l){
            num[a[i].id]=++tot,q.push({0,a[i].r,tot});
        }else{
            num[a[i].id]=q.top().id;
            Node tmp=q.top();
            q.pop(),q.push({0,a[i].r,tmp.id});
        }
    }
    printf("%d",tot);
    for(int i=1;i<=n;i++)
        printf("\n%d",num[i]);
    return 0;
}
